arguments.command:
# The .so itself likely has a symbol table (.dynsym) even if stripped. Let's check and try to symbolicate using it.
readelf -S /tmp/libmonosgen-2.0.so | grep -E 'dynsym|dynstr'
echo "---"
# Check if .dynsym has any entries
readelf --dyn-syms /tmp/libmonosgen-2.0.so 2>/dev/null | wc -l
echo "---"
# Try symbolicating the addresses using the dynamic symbol table
# Thread 1 (main): 0x222098, 0x2241ac, 0x1abc80, 0x16de04
# Thread 3 (SGen worker): 0x2f4b20, 0x2f4c84  
# Thread 4 (Finalizer): 0x2c1a40

# addr2line is for x86, we need a cross-platform approach. Let's try with aarch64 tools or nm
# Actually addr2line/objdump might not work for aarch64 on x86. Let me check
file /tmp/libmonosgen-2.0.so
echo "---"
# Try using readelf to find symbols near these addresses
for addr in 0x222098 0x2241ac 0x1abc80 0x16de04 0x2f4b20 0x2f4c84 0x2c1a40; do
    echo "=== Address: $addr ==="
    readelf --dyn-syms /tmp/libmonosgen-2.0.so 2>/dev/null | awk -v addr="$addr" '
    BEGIN { target = strtonum(addr); best_name = ""; best_addr = 0; best_offset = 999999999 }
    /FUNC/ {
        sym_addr = strtonum("0x" $2);
        sym_size = strtonum($3);
        if (sym_addr <= target && target < sym_addr + sym_size) {
            offset = target - sym_addr;
            if (offset < best_offset) {
                best_offset = offset;
                best_addr = sym_addr;
                best_name = $NF;
            }
        }
    }
    END {
        if (best_name != "") {
            printf "%s+0x%x (base: 0x%x)\n", best_name, best_offset, best_addr
        } else {
            print "NOT FOUND"
        }
    }'
done

